mod app;
mod bridge;
mod columns;
mod error;
mod format;
mod panic_hook;
mod poll;

// Generated by slint_build::compile in build.rs
slint::include_modules!();

use std::sync::Arc;

use parking_lot::Mutex;

fn main() -> Result<(), error::GuiError> {
    // 1. Install panic hook.
    panic_hook::install();

    // 2. Init tracing.
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "info".into()),
        )
        .with_target(false)
        .init();

    // 3. Load settings + column config.
    let config = irontide_config::load(None, &irontide_config::ConfigFile::default())
        .map_err(|e| error::GuiError::Config(e.to_string()))?;
    let gui_config = {
        let path = irontide_config::resolve_config_path(None);
        if path.exists() {
            let text = std::fs::read_to_string(&path).unwrap_or_default();
            let cf: irontide_config::ConfigFile =
                toml::from_str(&text).unwrap_or_default();
            cf.gui
        } else {
            irontide_config::GuiConfig::default()
        }
    };
    let col_config = columns::ColumnConfig::from_gui_config(&gui_config);
    let settings = config;

    // 4. Create shutdown channel + app state.
    let (shutdown_tx, shutdown_rx) = tokio::sync::oneshot::channel();
    let state = Arc::new(Mutex::new(app::AppState::new(shutdown_tx, col_config)));

    // 5. Create main window.
    let main_window = MainWindow::new()?;

    // 6. Wire menu callbacks.
    let weak = main_window.as_weak();
    let cb_state = state.clone();
    main_window.on_menu_file_action(move |index| {
        if let Some(action) = app::MenuAction::from_index(index) {
            bridge::handle_menu_action(action, &weak, &cb_state);
        }
    });

    // 6b. Wire sort callback.
    {
        let cb_state = state.clone();
        main_window.on_sort_requested(move |col_index| {
            let Some(col) = columns::ColumnId::from_index(col_index) else {
                return;
            };
            let mut st = cb_state.lock();
            if st.sort.column == col {
                st.sort.ascending = !st.sort.ascending;
            } else {
                st.sort.column = col;
                st.sort.ascending = true;
            }
        });
    }

    // 6c. Wire row-click callback.
    {
        let cb_state = state.clone();
        main_window.on_row_clicked(move |info_hash, shift, ctrl| {
            let hash = info_hash.as_str();
            let mut st = cb_state.lock();
            if ctrl {
                st.selection_ctrl_click(hash);
            } else if shift {
                st.selection_shift_click(hash);
            } else {
                st.selection_click(hash);
            }
        });
    }

    // 7. Spawn session thread.
    let session_handle = bridge::spawn_session_thread(
        settings,
        main_window.as_weak(),
        shutdown_rx,
        state.clone(),
    );

    // 8. Run Slint event loop (blocks until window is closed).
    main_window.run()?;

    // 9. Save column config if dirty.
    {
        let st = state.lock();
        if st.columns_dirty {
            let gui = st.columns.to_gui_config();
            if let Err(e) = irontide_config::save_gui_config(None, &gui) {
                tracing::warn!("failed to save GUI config: {e}");
            }
        }
    }

    // 10. Signal shutdown to background thread.
    if let Some(tx) = state.lock().shutdown_tx.take() {
        let _ = tx.send(());
    }

    // 11. Wait for background thread to finish.
    if let Err(e) = session_handle.join() {
        eprintln!("session thread panicked: {e:?}");
    }

    Ok(())
}
